INSERT INTO sourcebooks (name) VALUES ('Core'),('Custom'),('Settlers'),('Wanderers'),('Atom');
INSERT INTO special (name, description) VALUES
('Strength','Strength measures your character’s physical prowess. It is used to make melee attacks, increases melee damage, and influences how much stuff you can carry. Buy ranks in the Strength attribute if you want to be a strong character and solve your problems with force.'),
('Perception','Your perceptiveness influences how easily you notice danger and how aware you are of your environment, affects your turn in the initiative order in combat, and is used to make attacks with energy weapons. Buy ranks in the Perception attribute if you want to be a perceptive person and solve your problems by studying your surroundings.'),
('Endurance','Your natural toughness and resilience influences how many health points you have, how easy you find it to shrug off the physical dangers of the wasteland, and your ability to wield heavy weapons. Buy ranks in the Endurance attribute if you want to be hardy and resilient, and solve your problems by pushing through them.'),
('Charisma','Your natural charisma influences how effectively you can convince people of your opinions, change their minds, barter with people, and find safety among others. Buy ranks in the Charisma attribute if you want to be persuasive and solve problems by talking your way out of them.'),
('Intelligence','Your intelligence measures your smarts, how able you are to apply your mind to an obstacle, and how much you remember and know from studying the world around you. Buy ranks in the Intelligence attribute if you want to be cunning and clever, and solve your problems by thinking of the most effective solution.'),
('Agility','Your agility measures how fit and agile you are, your balance, athletic suppleness, and how precisely you can control your body. It is used to make ranged attacks with small guns. Buy ranks in the Agility attribute if you want to be nimble, and solve your problems with accuracy and skill.'),
('Luck','Luck describes just how much fortune smiles down on you, turning fickle forces in your favor, and generally coming out on top when you should be at the bottom. Luck gives you points to spend to add storydetails. Use your Luck attribute when you make skill tests, and re-roll dice.');
INSERT INTO traits (name,description) VALUES
('The Chain that Binds','You gain an additional Tag skill (must be Energy Weapons, Science, or Repair). You must carry out the orders of your immediate supervisors and are responsible for your subordinates.\n\nFailure to comply will result in expulsion and reclamation of gear.'),
('Necrotic Post-Human','You’re healed by Radiation damage (1HP/3Rad, reroll heal check when resting in irradiated locations). Survival becomes a Tag skill. You’re sterile, and will face discrimination from smoothskins.'),
('Forced Evolution','Your Strength and Endurance base and maximum are increased by +2. Your Intelligence and Charisma are capped at 6. You cannot have more than 4 ranks in any skill. You’re immune to Poison and Radiation. You’re sterile, and will face discrimination from non-Super Mutants.'),
('Mister Handy Robot','You have 360° vision and chemical sensors, reducing difficulty of perception tests that use sight or smell by 1. You’re immune to Poison and Radiation. You cannot use chems or benefit from food, drink, or rest. You’re unaffected by difficult terrain or obstacles. Your carry weight is 150lbs, and can only be increased with armor mods. You can only heal via repairs. You cannot Lockpick, Repair, Throw, make unarmed attacks, or manipulate objects without a Pincer arm attachment. Weapon arm attachments come with 20 rounds of ammunition for the weapon.'),
('Educated','You have +1 tag skill, but failing a non-tagged skill gives GM 1 AP.'),
('Fast Shot','If you take a second major action to make a ranged attack, it only costs 1 AP. You cannot Aim'),
('Gifted','Increase 2 SPECIAL by 1 each. Your maximum Luck points is LCK minus 1.'),
('Heavy Handed','Melee damage is +1CD. Melee and Un-armed suffer complications at 19+.'),
('Small Frame','You may reroll 1d20 on AGI that rely on balance/coordination. Carry weight is 150+(5*STR)lbs.'),
('Perk','Take an extra perk when selecting perks.'),
('Vault Kid','Difficulty of Endurance checks to resist disease are minus 1. You get +1 Tag skill. Work with GM to determine a psychological compli-cation. Overcoming this complica-tion restores one LCK.'),
('United We Stand','You gain Energy Weapons or Small Guns as a Tag skill. Your DR is +1 in cover, and you gain +1CD while outnumbered. Your settlements gain traders every 5 days and have a base Defense resource of 4.'),
('Good Natured','Tag 2 of: Speech, Medicine, Repair, Science, Barter. Maximum of all skills not listed is 4.'),
('Grunt','+1CD with SMGs, combat/assault rifles, frag grenades, and combat knives. Complication range of big guns or energy weapons is +2.'),
('Home on the Range','Resting by campfire 6+ hours decreases difficulty to recover from injuries by 1. You cannot gain Well Rested bonus.'),
('Trigger Discipline','Reroll 1d20 on small guns or energy weapons checks. Reduce their fire rate by 1.'),
('Brahmin Baron','Brahmin feed troughs provide upkeep for 3 brahmin. Tend Crops adds +1CD brahmin milk per feed trough.'),
('Protect or Destroy','Once per scene, reroll to overcome an environmental hazard. You’re immune to Poison and Radiation. You cannot benefit from chems/food/drink/rest. You can only heal via repairs. You can only have two robot mods installed at once. When making tests related to your model’s purpose, first d20 costs 0AP. Your carry weight is 225lbs and can only be increased with armor mods'),
('Robobrain Robot','Your visual sensors can detect infrared, ignoring darkness for Perception tests. You’re immune to Poison and Radiation. You can use your mesmetron to make ranged attacks. You cannot benefit from chems/food/drink/rest. You can only heal via repairs. Your carry weight is 150lbs and can only be increased with armor mods.'),
('Mk I Securitron','You’re immune to Poison and Radiation. You cannot benefit from chems/food/drink/rest. You can only heal via repairs. You move on a single tire; difficulty on tests to remain upright or balance is increased by 1. You have opposable claws on your arms and rudimentary weapons. Your shoulder-mounted missile launchers and grenade launcher are locked behind the MkII OS. Your carry weight is 150lbs and can only be increased with armor mods.'),
('More than Human','You gain +1 Tag skill. You do not suffer starvation or dehydration. You do not need sleep, and can perform minor activities during rest. You are immune to Poison, Radiation, and disease. You do not age.\n\nYou have a recall code.\n\nThe difficulty of CHA tests made by you or allies against those that know you’re a synth and are usympathetic is +2. Complications either start combat or decrease settlement reputation by 1.'),
('Rad Sponge','Your base Rad resistance is 1. Once per scene, you can take Radiation in someone Close’s stead. When taking Radiation (min 0), gain 1 Radiation Point (RP) (max 5). Spend RP to deal +2CD Radiation. Lose 1 RP when sleeping.'),
('Designed for the Frontline','Your limbs give you a +1CD to unarmed attacks in addition to STR bonuses. You can attack with claws or the built-in head laser. You can overload your core and self-destruct (this is not repairable). You’re immune to Poison and Radiation. You cannot benefit from chems/food/drink/rest. You can only heal via repairs. Your carry weight is 150lbs and can only be increased with armor mods.'),
('The Chain that Breaks','You gain an additional Tag skill (must be Energy Weapons, Science, or Repair). You gain +1d20 junk, and can spend 1AP 3x for +1 uncom-mon material. You can make 1 addi-tional roll on loot tables without spending AP.'),
('Stealth Boy Addict','Your Strength and Endurance base and maximum are increased by +2. Your Intelligence and Charisma are capped at 8. You cannot have more than 4 ranks in any skill. You’re immune to Poison and Radiation. You’re prone to Stealth Boy addic-tion. You’re sterile, and will face discrimination from non-Super Mutants.'),
('Mother Wasteland','Spend 1 Luck to gain cryptic/mystical insight (as if 3 AP spent to Obtain Information). Complications make pre-war artifacts harder to understand.'),
('Nomad','Reroll 1d20 on Survival to travel, setup camp, and forage. Ignore the first complication on these tests. Barter and Speech have +1 difficulty when dealing with settlers. Cannot Tag Science.'),
('Rite of Passage','Roll 1CD on first Luck use in each scene; effect negates Luck spend. Spend 1 AP to assist any PC that has not gone through your rite of passage.'),
('Tools of the Old World','Use Survival instead of Repair or Science to repair or use pre-war tech. Complication range involving pre-war tech is increased by 2.'),
('The Chosen One','The first d20 purchased for tests relating to your tribe’s quest is free, and you can auto-succeed at a cost. GM gets +2 AP when your quest comes up.');
