INSERT INTO perks (name,description,sourcebook_id,level_req,ranks,rank_range,reqs,limits) VALUES ('Action Boy/Girl','Additional major action does not increase difficulty','1','1','1','1','[]','[]'),
('Adamantium Skeleton','Damage required for crit +1','1','1','3','3','["endurance: 7"]','[]'),
('Adrenaline Rush','If HP<max, STR=10 for skills/melee','1','1','1','1','["strength: 7"]','[]'),
('Animal Friend','1: Mammals, Lizards and Insects roll 1CD on attack; non-effect means no attack. 2: CHA+Survival(2) as major action to befriend non-Mighty/Legendary','1','1','2','5','["charisma: 6"]','[]'),
('Aquaboy/Aquagirl','1: No more rad damage from swimming and double held breath 2: +2 difficulty to detect while underwater','1','1','2','3','["endurance: 5"]','[]'),
('Armorer','Unlock the equivalent rank of mods.','1','1','4','4','["strength: 5","intelligence: 6"]','[]'),
('Awareness','Aim at close range adds +1 Piercing','1','1','1','1','["perception: 7"]','[]'),
('Barbarian','Your DR increases with Melee Damage (STR 7-8=+1, 9-10=+2, 11+=+3)','1','4','1','1','["strength: 7"]','[]'),
('Basher','Gun bash gains Vicious','1','1','1','1','["strength: 6"]','[]'),
('Better Criticals','When you damage, spend Luck to crit','1','1','1','1','["luck: 9"]','[]'),
('Big Leagues','Two-handed melee gains Vicious','1','1','1','1','["strength: 8"]','[]'),
('Black Widow/Lady Killer','Pick a gender. Against that gender, reroll 1d20 on CHA and +1CD damage.','1','1','1','1','["charisma: 6"]','[]'),
('Blacksmith','Unlock the equivalent rank of mods.','1','2','3','4','["strength: 6"]','[]'),
('Blitz','1: Reroll 1d20 on attack when close in and melee in one turn. 2: +1CD on that attack.','1','1','2','3','["agility: 9"]','[]'),
('Bloody Mess','Roll 1CD when crit; effect=+1 crit.','1','1','1','1','["luck: 6"]','[]'),
('Can Do!','Find 1 more food while scavenging.','1','1','1','1','["luck: 5"]','[]'),
('Cap Collector','Buy/sell prices 10% more favorable.','1','1','1','1','["charisma: 5"]','[]'),
('Cautious Nature','Reroll 1d20 when buying more d20s with AP.','1','1','1','1','["perception: 7"]','["no Daring Nature perk"]'),
('Center Mass','Choosing torso does not raise difficulty. Reroll 1d20.','1','1','1','1','["agility: 7"]','[]'),
('Chem Resistant','1: -1CD to determine addiction. 2: Cannot become addicted to chems.','1','1','2','4','["endurance: 7"]','[]'),
('Chemist','Chems you make last twice as long. Unlocks chem recipes.','1','1','1','1','["intelligence: 7"]','[]'),
('Commando','+1CD/rank to fire rate 3+ weapon.','1','2','2','3','["agility: 8"]','[]'),
('Comprehension','Roll 1CD to extend magazine bonus.','1','1','1','1','["intelligence: 6"]','[]'),
('Concentrated Fire','Reroll 3CD when you spend ammo to increase damage','1','1','1','1','["perception: 8","agility: 6"]','[]'),
('Daring Nature','Reroll 1d20 when buying more d20s with GM AP','1','1','1','1','["luck: 7"]','["no Cautious Nature perk"]'),
('Demolition Expert','Blast weapons gain Vicious. Unlocks explosives recipes.','1','1','1','1','["perception: 6","luck: 6"]','[]'),
('Dodger','1: Defend difficulty -1. 2: -1AP cost to increase defense.','1','4','2','6','["agility: 6"]','[]'),
('Dogmeat','You have a pet dog.','1','1','1','1','["charisma: 5"]','[]'),
('Entomologist','+1 Piercing against Insects.','1','1','1','1','["intelligence: 7"]','[]'),
('Fast Metabolism','Non-rest healing +1/rank','1','1','3','3','["endurance: 6"]','["robot"]'),
('Faster Healing','First d20 END+Survival to heal self is free (maximum still 5d20).','1','1','1','1','["endurance: 6"]','["robot"]'),
('Finesse','Reroll all CD once/combat for free','1','1','1','1','["agility: 9"]','[]'),
('Fortune Finder','+3CDc while looting; +6CDc; +10CDc','1','2','3','4','["luck: 5"]','[]'),
('Ghost','First d20 AGI+Sneak in dark is free (maximum still 5d20).','1','1','1','1','["perception: 5","agility: 6"]','[]'),
('Grim Reaper’s Sprint','Roll 1CD when you kill an enemy. Add 2AP on an effect.','1','1','1','1','["luck: 8"]','[]'),
('Gun Fu','On ranged hit, spend (Rank)AP and (Rank)Ammo to hit (Rank) targets within close range of the first target. Each takes same damage as first.','1','1','3','5','["agility: 10"]','[]'),
('Gun Nut','Unlock the equivalent rank of mods.','1','2','4','4','["intelligence: 6"]','[]'),
('Gunslinger','+(Rank)CD with 1H ranged fire rate 2 or less. Reroll hit location.','1','2','2','4','["agility: 7"]','[]'),
('Hacker','-1 Difficulty to hack.','1','1','1','1','["intelligence: 8"]','[]'),
('Healer','+(Rank) healing with First Aid.','1','1','3','5','["intelligence: 7"]','[]'),
('Heave Ho!','Spend 1AP to increase throw range.','1','1','1','1','["strength: 8"]','[]'),
